const d1  = $('Buscar Hoje').first().json;
const d7  = $('Buscar Semana').first().json;
const d30 = $('Buscar 30 dias').first().json;
const d90 = $input.first().json;

function fmt(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m + '/' + y;
}
function fmtShort(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m;
}
function brl(v) {
  const num = parseFloat(v);
  const parts = Math.abs(num).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}
function pct(a, b) {
  if (!b) return '0,00';
  return (a / b * 100).toFixed(2).replace('.', ',');
}
function deltaLabel(v) {
  return parseFloat(v) >= 0 ? 'um delta positivo de' : 'um delta negativo de';
}
function finHoje(f) {
  return 'Hoje foram depositados ' + brl(f.depositos) + ' com ' + brl(f.saques) + ' de saques totalizando ' + deltaLabel(f.delta) + ' ' + brl(f.delta) + '.';
}
function finPeriodo(f) {
  return 'Nesse período foram depositados um total de ' + brl(f.depositos) + ' com ' + brl(f.saques) + ' de saques totalizando ' + deltaLabel(f.delta) + ' ' + brl(f.delta) + '.';
}

const meses = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
function fmtMes(s) {
  const [y, m] = s.split('-');
  return meses[parseInt(m, 10) - 1] + '/' + y;
}

const u1 = d1.usuarios;
const taxaConversao = Math.round(u1.investindo / u1.total * 100);
const usuariosHoje = u1.novos > 0
  ? 'Hoje tivemos ' + u1.novos + ' novos cadastros, totalizando ' + u1.total + ' usuários na plataforma. Destes, ' + u1.investindo + ' são investidores, representando uma taxa de conversão de ' + taxaConversao + '%.'
  : 'Não houve novos cadastros hoje. A base permanece com ' + u1.total + ' usuários, sendo que ' + u1.investindo + ' estão investindo, representando uma taxa de conversão de ' + taxaConversao + '%.';

function usuariosPeriodo(u) {
  const base = u.total - u.novos;
  return 'Foram criados ' + u.novos + ' novos usuários nesse período, um aumento de ' + pct(u.novos, base) + '%.';
}

const pendentes = d1.financeiro.saques_pendentes || 0;
const saquesPendentesLinha = pendentes > 0
  ? 'Saques pendentes: ' + pendentes
  : 'Não temos nenhum saque pendente.';

const projecao = (d1.projecao_6_meses || []).map(function(p) {
  return fmtMes(p.mes) + ': ' + brl(p.total_previsto);
}).join('\n');

const estrutura = [
  '*Resumo Operacional - ' + fmt(d1.data_referencia) + '*',
  '',
  '*Diário*',
  '',
  usuariosHoje,
  '',
  'O valor investido apenas pelos nossos usuários totaliza ' + brl(d1.financeiro.volume_investido) + '.',
  '',
  finHoje(d1.financeiro),
  '',
  saquesPendentesLinha,
  '',
  '*Últimos 7 dias* (' + fmtShort(d7.data_inicio) + ' a ' + fmtShort(d7.data_referencia) + ')',
  '',
  usuariosPeriodo(d7.usuarios),
  '',
  finPeriodo(d7.financeiro),
  '',
  '*Últimos 30 dias* (' + fmtShort(d30.data_inicio) + ' a ' + fmtShort(d30.data_referencia) + ')',
  '',
  usuariosPeriodo(d30.usuarios),
  '',
  finPeriodo(d30.financeiro),
  '',
  '*Últimos 90 dias* (' + fmtShort(d90.data_inicio) + ' a ' + fmtShort(d90.data_referencia) + ')',
  '',
  usuariosPeriodo(d90.usuarios),
  '',
  finPeriodo(d90.financeiro),
  '',
  '*Projeção das Metas (6 meses)*',
  '',
  projecao || 'Nenhuma meta ativa configurada.',
].join('\n');

const chatInput = [
  'Voce e um assistente executivo da Purg.',
  'Com base nos dados abaixo, escreva EXATAMENTE 2 paragrafos curtos e suscintos de analise comparativa.',
  'Cada paragrafo deve ter no maximo 2 frases. Cubra angulos diferentes: um sobre usuarios, outro sobre financeiro.',
  'Regras: texto simples, sem asteriscos, sem markdown, sem introducao, sem assinatura.',
  '',
  estrutura,
].join('\n');

return [{ json: { estrutura, chatInput } }];

const analise = $input.first().json.text || $input.first().json.output || '';
const estrutura = $('Monta Prompt').first().json.estrutura;
const texto = estrutura + '

*Análise da Purg*

' + analise + '

Atenciosamente,
Purg';
return [{ json: { text: texto } }];

